def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.sqrt((point1[0] - point2[0])**2 + (point1[1] - point2[1])**2)

    best_node = None
    lowest_risk = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = distance(cur_truck_pos, customer_pos) / truck_speed
        predicted_arrival = current_time + travel_time
        start_time, end_time = time_windows[i]

        # Calculating the risk of not meeting time window
        if predicted_arrival <= start_time:
            risk = start_time - predicted_arrival  # early arrival risk is just waiting time
        elif predicted_arrival > end_time:
            risk = (predicted_arrival - end_time) ** 2  # very high risk for late arrival
        else:
            risk = 0  # no risk if on time

        # Adjust risk by availability of nearby trucks to take over the task if needed
        backup_trucks = sum(1 for pos in all_truck_pos if distance(pos, customer_pos) < (truck_speed * (end_time - current_time + 0.5)))
        risk /= (backup_trucks + 1)  # divide risk by the count of available backup trucks+1 (including itself)

        if risk < lowest_risk:
            lowest_risk = risk
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(start, end):
        return np.linalg.norm(end - start) / truck_speed

    def urgency_score(time_window):
        start, end = time_window
        if current_time > end:
            return float('inf')  # Very high penalty for missed time windows
        else:
            return max(0, end - current_time)  # Less urgent if more time available

    best_node = None
    min_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        urgency = urgency_score(time_windows[i])
        # Prioritize by combining the travel time with urgency and adding weighted urgency
        cost = travel_time + 10 * urgency

        if cost < min_cost:
            min_cost = cost
            best_node = i

    return best_node
